def to_binary(n):
    if n == 0:
        return '0'
    result = ''
    while n > 0:
        result = str(n % 2) + result
        n //= 2
    return result


def to_hex(n):
    if n == 0:
        return '0'
    hex_chars = '0123456789ABCDEF'
    result = ''
    while n > 0:
        result = hex_chars[n % 16] + result
        n //= 16
    return result


def from_binary(binary_str):
    result = 0
    for digit in binary_str:
        result = result * 2 + int(digit)
    return result


def from_hex(hex_str):
    hex_chars = '0123456789ABCDEF'
    result = 0
    for ch in hex_str.upper():
        result = result * 16 + hex_chars.index(ch)
    return result
